sys_script_include.script:
var api_tasker_task = Class.create();
api_tasker_task.CONST_DTECH_DURATION_OBJECT = "durationObject";
api_tasker_task.CONST_DTECH_ITEM_MEMBERS_OBJECT = "itemMembersObject";
api_tasker_task.CONST_DTECH_OFFICE_OBJECT = "officeObject";
api_tasker_task.CONST_DTECH_OPERATIONAL_OBJECT = "operationalObject";
api_tasker_task.CONST_DTECH_RESPONSE_OBJECT = "responseObject";
api_tasker_task.CONST_DTECH_STATE_OBJECT = "stateObject";
api_tasker_task.CONST_DTECH_SUB_TASKS_OBJECT = "subtasksObject";
api_tasker_task.CONST_DTECH_TASKER_FILES_OBJECT = "taskerFilesObject";
api_tasker_task.CONST_DTECH_TASK_CONTEXT_MENU_ACTIONS_OBJECT = "ContextMenuActionsObject";
api_tasker_task.CONST_DTECH_TASK_TREE_OBJECT = "taskTreeObject";
api_tasker_task.prototype = {
    initialize: function() {
		this.api_dtech = new api_dtech_common();
		this.taskerStatus = new TaskerStatus();
		this.taskTable = "x_153465_discovert_route_task_instance";
		this.requestTable = "x_153465_discovert_tasker_requests";
		this.titleField = "task_name";
    },

	// NOTE: the getUIActions function is not in the inital load yet.
	//       Looking for a way to use $sp.getForm from here
	getTaskRecordObjects: function(taskId, arrObjectList){
		var taskRecordObject = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			if(arrObjectList){
				if(arrObjectList[api_tasker_task.CONST_DTECH_OFFICE_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_OFFICE_OBJECT] = this.getAssignmentInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_DURATION_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_DURATION_OBJECT] = this.getDurationInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_ITEM_MEMBERS_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_ITEM_MEMBERS_OBJECT] = this.getItemMembersInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_OPERATIONAL_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_OPERATIONAL_OBJECT] = this.getOperationalInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_RESPONSE_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_RESPONSE_OBJECT] = this.getResponseCommentsGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_STATE_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_STATE_OBJECT] = this.getStateInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_SUB_TASKS_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_SUB_TASKS_OBJECT] = this.getSubTasksInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_TASKER_FILES_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_TASKER_FILES_OBJECT] = this.getTaskerFilesInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_TASK_TREE_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_TASK_TREE_OBJECT] = this.getTaskTreeInformationGR(gr_task);
				}
				if(arrObjectList[api_tasker_task.CONST_DTECH_TASK_CONTEXT_MENU_ACTIONS_OBJECT]){
					taskRecordObject[api_tasker_task.CONST_DTECH_TASK_CONTEXT_MENU_ACTIONS_OBJECT] = 
						this.getContextMenuInformationGR(gr_task);
				}
			}
		}
		return taskRecordObject;
	},

	getAssignmentInformation: function(taskId){
		var lAssignmentInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lAssignmentInfo = this.getAssignmentInformationGR(gr_task);
		}
		return lAssignmentInfo;
	},

	getAssignmentInformationGR: function(gr_task){
		var lAssignmentInfo = {};
		// NOTE: warning hours is actually a number of days, not hours
		// NOTE: calendar duration is Estimated Effort
		var arrAssignmentFields = 
			["task_name", "tasking_authority", "u_reviewer", "primary_office", "u_task_requester", "primary_assignee", 
			"assigned_to", "u_internal_contact_performing_task", "u_internal_contact", "on_behalf_of", 
			"outbound", "u_external_ou", "poc_name", "external_task_id_number", "u_external_task_url", 
			"originator", "sys_created_on"];

		lAssignmentInfo = this.api_dtech.loadObject(gr_task, arrAssignmentFields);
		// add task id after loaded
		lAssignmentInfo.taskId = gr_task.getUniqueValue();
		// NOTE: if the task is not an outbound task, remove outbound and external fields
		if(lAssignmentInfo.outbound!=true){
			lAssignmentInfo["outbound"] = undefined;
			lAssignmentInfo["u_external_ou"] = undefined;
			lAssignmentInfo["poc_name"] = undefined;
			lAssignmentInfo["external_task_id_number"] = undefined;
			lAssignmentInfo["u_external_task_url"] = undefined;
		}
		var title = gr_task.getDisplayValue(this.titleField);
		lAssignmentInfo.assignmentTitle = gs.getMessage('Tasker - Title - Assignment Modal') + ': ' + title;
		return lAssignmentInfo;		
	},

	getContextMenuInformation: function(taskId){
		var lContextMenuInformation = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lContextMenuInformation = this.getContextMenuInformationGR(gr_task);
		}
		return lContextMenuInformation;
	},

	// NOTE: this one is backward where if we have the glide record we get the task id and call getContextMenuInformation
	getContextMenuInformationGR:function (gr_task){
		var lContextMenuInformation = {};
		var taskId = gr_task.getUniqueValue();

		var arrContextMenuFields = 
			["active"];
		lContextMenuInformation = this.api_dtech.loadObject(gr_task, arrContextMenuFields);		
		var form = $sp.getForm(this.taskTable, taskId);
		var ui_actions = form._ui_actions;
		lContextMenuInformation.ui_actions = this._load_context_ui_actions(ui_actions, gr_task);
		lContextMenuInformation.taskId = taskId;
		return lContextMenuInformation;
	},

	getDurationInformation: function(taskId){
		var lDurationInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lDurationInfo = this.getDurationInformationGR(gr_task);
		}
		return lDurationInfo;
	},

	getDurationInformationGR: function(gr_task){
		var lDurationInfo = {};
		// NOTE: warning hours is actually a number of days, not hours
		// NOTE: calendar duration is Estimated Effort
		var arrDurationFields = 
			["task_name", "suspense_date", "task_order", "warning_hours", "u_wait_for_subtasks_to_finish", "expected_start", "calendar_duration", 
			"work_start", "work_end", "outbound", "u_external_due_date", "status"];
		lDurationInfo = this.api_dtech.loadObject(gr_task, arrDurationFields);
		var status_and_reason = {};
		status_and_reason = this.taskerStatus.getStatusAndReason(gr_task);
		lDurationInfo.status_reason = status_and_reason;
		// add task id after loaded
		lDurationInfo.taskId = gr_task.getUniqueValue();
		// NOTE: if the task is not an outbound task, remove outbound and external due date
		if(lDurationInfo.outbound!=true){
			lDurationInfo["outbound"] = undefined;
			lDurationInfo["u_external_due_date"] = undefined;
		}
		var title = gr_task.getDisplayValue(this.titleField);
		// 2.8.5 | 2023-11-07 | mmcc | STRY0145237 - Directive - Duration code changes to match design; removed ': '
		lDurationInfo.durationTitle = gs.getMessage('Tasker - Title - Duration Modal') + title;
		return lDurationInfo;
	},

	getItemMembersInformation: function(taskId){
		var lItemMembersInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lItemMembersInfo = this.getItemMembersInformationGR(gr_task);
		}
		return lItemMembersInfo;
	},

	getItemMembersInformationGR: function(gr_task){
		var lItemMembersInfo = {};
		var lMembers = {};
		var arrMembers = [];
		var arrItemMembersFields = 
			["assigned_to", "originator", "u_task_requester", "u_reviewer", "on_behalf_of"];
		lMembers = this.api_dtech.loadObject(gr_task, arrItemMembersFields);

		// NOTE: additional fields are needed in the member info object, add them after loading the members into an array with photos
		// turn the member field object into an array and add the photos
		arrMembers = this._loadPhotosForObjects(lMembers, arrItemMembersFields);
		lItemMembersInfo.members = arrMembers;

		// add task id after loaded
		lItemMembersInfo.taskId = gr_task.getUniqueValue();
		var title = gr_task.getDisplayValue(this.titleField);
		lItemMembersInfo.itemMembersTitle = gs.getMessage('Tasker - Title - ItemMembers Modal') + ': ' + title;

		return lItemMembersInfo;
	},

	getOperationalInformation: function(taskId){
		var lOperationalInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lOperationalInfo = this.getOperationalInformationGR(gr_task);
		}
		return lOperationalInfo;
	},

	getOperationalInformationGR: function(gr_task){
		var lOperationalInfo = {};
		var lTopTasklInfo = {};
		// NOTE: warning hours is actually a number of days, not hours
		// NOTE: calendar duration is Estimated Effort
		var arrOperationalFields = 
			["task_name", "number", "parent", "taskernumber", "classification", "assignement_group", "tasker_type", "short_description", 
			"instructions", "priority", "state", "urgency",
			"status", "category", "sub_category", "risk_flag", "risk_impact_description",
			"risk_impact_factor", "risk_mitigation_strategy", "risk_probability", "risk_probability_description", "risk_reason",
			"tasker_app_version"];
		var arrTopTaskFields = ["u_objective"];

		lOperationalInfo = this.api_dtech.loadObject(gr_task, arrOperationalFields);
		var status_and_reason = {};
		status_and_reason = this.taskerStatus.getStatusAndReason(gr_task);
		lOperationalInfo.status_reason = status_and_reason;
		// add task id after loaded
		lOperationalInfo.taskId = gr_task.getUniqueValue();
		var title = gr_task.getDisplayValue(this.titleField);


		lTopTasklInfo = this._getTopTaskFields(gr_task, arrTopTaskFields);
		lOperationalInfo.u_top_task = lTopTasklInfo;
		lOperationalInfo.operationalTitle = gs.getMessage('Tasker - Title - Operational Modal') + ': ' + title;		
		return lOperationalInfo;
	},

	getResponseComments: function(taskId){
		var lResponseCommentsInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lResponseCommentsInfo = this.getResponseCommentsGR(gr_task);
		}
		return lResponseCommentsInfo;
	},

	getResponseCommentsGR: function(gr_task){
		var lResponseCommentsInfo = {};
		lResponseCommentsInfo.directive_reopen_comments = '';
		lResponseCommentsInfo.directive_response_comments = '';
		lResponseCommentsInfo.directive_reviewer_comments = '';
		lResponseCommentsInfo.directive_rework_comments = '';

		// View Comment on Detailed Status; added
		lResponseCommentsInfo.directive_content_comment = '';

		lResponseCommentsInfo.isResponseCommentsDirectiveShown = false;

		// use one var in ngIf for Response Comments Directive
		if (gr_task.getElement('comments_dt').getDisplayValue().length > 0 ||
			gr_task.getElement('response').getDisplayValue().length > 0 ||
			gr_task.getElement('reopen_comments').getDisplayValue().length > 0 ||
			gr_task.getElement('rework_comments').getDisplayValue().length > 0) {
			lResponseCommentsInfo.isResponseCommentsDirectiveShown = true;
			lResponseCommentsInfo.directive_reopen_comments = gr_task.getElement('reopen_comments').getDisplayValue();
			lResponseCommentsInfo.directive_response_comments = gr_task.getElement('response').getDisplayValue();
			lResponseCommentsInfo.directive_reviewer_comments = gr_task.getElement('comments_dt').getDisplayValue();
			lResponseCommentsInfo.directive_rework_comments = gr_task.getElement('rework_comments').getDisplayValue();
		}

		// 2.8.5 | 2023-07-07 | mmcc | STRY0137651 - When to Show Comments on Final Response Tab; added, get returns a string
		if (gr_task.getElement('work_item_type').getDisplayValue() == 'review_item') {
			lResponseCommentsInfo.directive_content_comment = lResponseCommentsInfo.directive_reviewer_comments;
		} else {
			lResponseCommentsInfo.directive_content_comment = lResponseCommentsInfo.directive_response_comments;
		}
		return lResponseCommentsInfo;
	},

	getStateInformation: function(taskId){
		var lStateInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lStateInfo = this.getStateInformationGR(gr_task);
		}
		return lStateInfo;
	},

	getStateInformationGR: function(gr_task){
		var lStateInfo = {};
		// NOTE: warning hours is actually a number of days, not hours
		// NOTE: calendar duration is Estimated Effort
		var arrStateFields = 
			["state"];
		lStateInfo = this.api_dtech.loadObject(gr_task, arrStateFields);
		// add task id after loaded
		lStateInfo.taskId = gr_task.getUniqueValue();
		return lStateInfo;
	},

	getSubTasksInformation: function(taskId){
		var lSubTasksInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lSubTasksInfo = this.getSubTasksInformationGR(gr_task);
		}
		return lSubTasksInfo;
	},

	getSubTasksInformationGR: function(gr_task){
		var lSubTasksInfo = {};
		var arrSubTasksFields = 
			["calchaschildren"];
		lSubTasksInfo = this.api_dtech.loadObject(gr_task, arrSubTasksFields);
		// add task id after loaded
		lSubTasksInfo.taskId = gr_task.getUniqueValue();
		var title = gr_task.getDisplayValue(this.titleField);
		lSubTasksInfo.subTasksTitle = gs.getMessage('Tasker - Title - SubTasks Modal') + ': ' + title;
		return lSubTasksInfo;
	},

	getSubTasksInformationWithList: function(taskId){
		var lSubTasksInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lSubTasksInfo = this.getSubTasksInformationWithListGR(gr_task);
		}
		return lSubTasksInfo;
	},

	getSubTasksInformationWithListGR: function(gr_task){
		var lSubTasksInfo = {};
		// load the subtask information
		lSubTasksInfo = this.getSubTasksInformationGR(gr_task);
		// array of subtasks
		var lsubtasks = [];
		lsubtasks = this._getSubTaskList(gr_task);
		lSubTasksInfo.subtasks = lsubtasks;
		return lSubTasksInfo;
	},

	getTaskerFilesInformation: function(taskId){
		var lTaskerFilesInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lTaskerFilesInfo = this.getTaskerFilesInformationGR(gr_task);
		}
		return lTaskerFilesInfo;
	},

	getTaskerFilesInformationGR: function(gr_task){
		var lTaskerFilesInfo = {};
// TODO - NEED TO GET NEW FIELD IN FOR DOCUMENT COUNTS
		var arrSubTasksFields = 
			["calchaschildren"];
		lTaskerFilesInfo = this.api_dtech.loadObject(gr_task, arrSubTasksFields);
// TODO - NEED TO ADD A CHECK FOR DOCUMENT VS ATTACHMENT SETTING		
		// add task id after loaded
		lTaskerFilesInfo.taskId = gr_task.getUniqueValue();
// TODO - SET TO DOCUMENTS OR ATTACHMENTS BASED ON TASKER SYSTEM SETTINGS 
// NOTE: if both is on, do we say files instead of having 2 headers?
// NOTE: do we have something per view or multiple lists in the dropdown, or just show the items associated iwth this file and have the tree have an attachments icon for the tree level folders
		lTaskerFilesInfo.label = gs.getMessage('Tasker - Documents');
		var title = gr_task.getDisplayValue(this.titleField);
		lTaskerFilesInfo.title = gs.getMessage('Tasker - Title - SubTasks Modal') + ': ' + title;
		return lTaskerFilesInfo;
	},

	getTaskerFilesInformationWithFiles: function(taskId){
		var lTaskerFilesInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lTaskerFilesInfo = this.getTaskerFilesInformationWithFilesGR(gr_task);
		}
		return lTaskerFilesInfo;
	},

	getTaskerFilesInformationWithFilesGR: function(gr_task){
		var lTaskerFilesInfo = {};
		// load the subtask information
		lTaskerFilesInfo = this.getTaskerFilesInformationGR(gr_task);
		// array of files
		var ltaskerfiles = [];
// TODO - BUILD FILE NAME LOADER AND ALSO DETERMINE IF WE HAVE MULTIPLE FOLDERS AND IF WE ALSO LOAD THE SIGNATURE IN HERE
		ltaskerfiles = this._getSubTaskList(gr_task);
		lTaskerFilesInfo.files = ltaskerfiles;
		return lTaskerFilesInfo;
	},

	getTaskTreeInformation: function(taskId){
		var lTaskTreeInfo = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			lTaskTreeInfo = this.getTaskTreeInformationGR(gr_task);
		}
		return lDurationInfo;
	},

	getTaskTreeInformationGR: function(gr_task){
		var lTaskTreeInfo = {};
		// NOTE: warning hours is actually a number of days, not hours
		// NOTE: calendar duration is Estimated Effort
		var arrStateFields = 
			["u_task_tree"];
		lTaskTreeInfo = this.api_dtech.loadObject(gr_task, arrStateFields);
		// add task id after loaded
		lTaskTreeInfo.taskId = gr_task.getUniqueValue();
		return lTaskTreeInfo;
	},

	getUIActionParamaters: function(taskId, action_name, action_sys_id){
		var params = {};
		var gr_task = new GlideRecordSecure(this.taskTable);
		if(gr_task.get(taskId)){
			params = this.getUIActionParamatersGR(gr_task, action_name, action_sys_id);
		}
		return params;
	},

	getUIActionParamatersGR: function(gr_task, action_name, action_sys_id){
		var params = {};
		var objTaskActions = this._get_ui_actions_icons();
		var arrItem = Object.keys(objTaskActions).filter(function(key){
			return objTaskActions[key].action_name==action_name || key==action_sys_id;});
		if(arrItem[0]){
			// get the key b/c the sys_id is the key of the array
			var ui_action_sys_id = arrItem[0];
			// load ui action parameters
			params = this._get_ui_actions_params(gr_task, ui_action_sys_id);
		}
		return params;
	},

	publishTask: function(task_sys_id) {
		var publishResponse = {};
		publishResponse.taskPublished = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_task = new GlideRecord(this.taskTable);
		if(gr_task.get(task_sys_id)){
			new Task_uiAction().uiAction_PublishDraftTasks(gr_task, 'taskOnly');
			publishResponse.taskPublished = true;
		}
		return publishResponse;
	},

	_getParentTaskFields: function(gr_task, arrParentTaskFields){
		var parentTaskId = gr_task.getValue("parent");
		var gr_parent_task = new GlideRecordSecure(this.taskTable);
		var lParentTasklInfo;
		if(gr_parent_task.get(parentTaskId)){
			lParentTasklInfo = this.api_dtech.loadObject(gr_task, arrParentTaskFields);
		}
		return lParentTasklInfo;
	},

	_loadPhotosForObjects: function(infoObject, fields){
		var arrMembers = [];
		var userInfo = new UserInfoScripts();
		for (i=0; i < fields.length; i++) {
			var fieldName = fields[i];
			var field = infoObject[fieldName];
			field.order = i;
			if(field.value && field.value!=null && field.value!="null"){
				field.photoInfo = userInfo.loadPhotoInfo(field.value, true);
			}
			arrMembers.push(field);
		}
		return arrMembers;
	},

	_getSubTaskList: function(gr_task){
		var lSubTaskInfo = {};
		var lSubTasks = [];
		var arrSubTaskListFields = 
			["short_description", "state", "number"];

		var gr_subtasks = new GlideRecordSecure(this.taskTable);
		gr_subtasks.addQuery("parent", gr_task.getUniqueValue());
		gr_subtasks.query();
		while(gr_subtasks.next()){
			lSubTaskInfo = this.api_dtech.loadObject(gr_subtasks, arrSubTaskListFields);
			// add task id after loaded
			lSubTaskInfo.taskId = gr_subtasks.getUniqueValue();
			lSubTasks.push(lSubTaskInfo);
		}
		return lSubTasks;
	},

	_getTopTaskFields: function(gr_task, arrTopTaskFields){
		var topTaskId = gr_task.getValue("u_top_task");
		var gr_top_task = new GlideRecordSecure(this.taskTable);
		var lTopTasklInfo;
		if(gr_top_task.get(topTaskId)){
			lTopTasklInfo = this.api_dtech.loadObject(gr_task, arrTopTaskFields);
		}
		return lTopTasklInfo;
	},

	// NOTE: if we can move icons to an attachment on the ui action, we could reduce this to filtering out separators and pull all list context menu actions
	_load_context_ui_actions: function(form_ui_actions, gr_task){
		var arrMenuItems = [];
		var ui_action_menu_item = {};
		var arrHCMUI = this._get_ui_actions_context_menu_array();
		// load ui action icons
		var ui_actions_icons = this._get_ui_actions_icons();
		var orderCount = 0;
		for (actionIndex=0; actionIndex < arrHCMUI.length; actionIndex++) {
			var addAction = false;
			var hcm_item = arrHCMUI[actionIndex];
			if(hcm_item != "separator"){
				var arrItem = form_ui_actions.filter(function(item){
					return item.sys_id==hcm_item;});
				// if the action was not returned, then the user doesn't have permsissions, don't add it
				if(arrItem[0]){
					addAction=true;
					ui_action_menu_item = arrItem[0];
					ui_action_menu_item.order = actionIndex;
					ui_action_menu_item.image = undefined;
					var ui_action_icon = ui_actions_icons[ui_action_menu_item.sys_id];
					if(ui_action_icon){
						ui_action_menu_item.image = ui_action_icon.image;
					}
					var params = {};
					// load ui action parameters
					params = this._get_ui_actions_params(gr_task, ui_action_menu_item.sys_id);
					ui_action_menu_item.params = params;
				}
			} else {
				addAction=true;
				ui_action_menu_item = {
					"sys_id" : "separtor" + actionIndex.toString(),
					"name": "separator",
					"order": actionIndex
				};
			}
			if(addAction){
				arrMenuItems.push(ui_action_menu_item);				
			}
		}
		// now filter out adjacent separators
		var prevIsSeparator = false;  // defined outside the function so it keeps a flag if the previous item is a spearator
		arrMenuItems = arrMenuItems.filter(function(item){
			var include=true;
			if(prevIsSeparator && item.name=="separator"){
				// this item and previous are both separators.  Skip and do not include
				include = false;
			}
			prevIsSeparator = item.name=="separator";
			return include;
		});
		// remove leading separators
		while(arrMenuItems.length>0 && arrMenuItems[0].name=="separator"){
			arrMenuItems.shift();
		}
		while(arrMenuItems.length>0 && arrMenuItems[arrMenuItems.length-1].name=="separator"){
			arrMenuItems.pop();
		}
		return arrMenuItems;
	},

	// this returns an object with just the id, but could return more data later
	// NOTE: to allow multiple requests, we would need to update this
	_get_task_request: function(task_id, requestType, status){	
		var requestInfo = {};

		var gr = new GlideRecordSecure(this.requestTable);
		gr.addQuery('parent', task_id);
		gr.addQuery('u_request_type', requestType);
		gr.addQuery('u_status', status);
		gr.query();

		while(gr.next()){
			requestInfo.request_sys_id = gr.getUniqueValue();
		}
		return requestInfo;
	},

