	_get_ui_actions_params: function(gr_task, action_sys_id){
		var params = {};
		var requestInfo = {};
		switch (action_sys_id){
			case '9e53d1f8db02f01087f2892d139619ed': // "name": "Delete", (task), "action_name" : "delete_tasks"
				params.action_name = "delete_tasks";
				params.task_sys_id = gr_task.getUniqueValue();
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Delete') + ' ' + params.number_name + '?';
				break;
			case '18b25020db9a5890dd3d6165ca961972': // "name": "Publish Task(s)", "action_name" : "publish_tasks"
				params.action_name = "publish_tasks";
				params.task_sys_id = gr_task.getUniqueValue();
				// making these objects allows us to just load fields in the ui action function
				params.state = gr_task.getValue("state");
				params.calchaschildren = gr_task.getValue("calchaschildren");
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Tasker - Title - Publish Selection for') + params.number_name;
				break;
			case '6ca12aa7db052f88c18c59b2ca96192a': // name: "Reject", "action_name": "Reject-Approval"
				params.action_name = "Reject-Approval";
				params.task_sys_id = gr_task.getUniqueValue();
				params.comments_dt = gr_task.getDisplayValue('comments_dt');
				if(!params.comments_dt || params.comments_dt==null){
					params.comments_dt = '';
				}
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = params.number_name + '?';
				// this is tasker_type value
				var taskType = gr_task.getDisplayValue("tasker_type.u_value");
				var taskerTypesConstants = new TaskerTypes().getValueConstants();
				if (taskType == taskerTypesConstants.approval_with_signature){
					params.title = gs.getMessage('Tasker - Title - Rejection for Approval with Signature') + ' ' + params.number_name + '?';
				} else if (taskType == taskerTypesConstants.approval) {
					params.title = gs.getMessage('Tasker - Title - Rejection for Approval without Signature') + ' ' + params.number_name + '?';
				}
				break;
			case 'd237f7974fa28300303dc3818110c7c4': // "name": "Reopen Task", "action_name": "Reopen"
				params.action_name = "Reopen";
				params.task_sys_id = gr_task.getUniqueValue();
				params.active = gr_task.getDisplayValue('active');
				params.number = gr_task.getValue('number');
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Tasker - Title - Reopen Selection for') + params.number_name;
				// initialize parent fields
				params.parent_sys_id = '';
				params.parent_active = '';
				params.parent_number = '';

				if (!gr_task.parent.nil()){
					var arrParentTaskFields = ["sys_id", "active", "number"];
					var lParentTasklInfo = this._getParentTaskFields(gr_task, arrParentTaskFields);
					params.parentInfo = lParentTasklInfo;

					// parent logic - also in Business Rule Tasker - Tasker - onLoad - set max routes
					// if we do api call back in the UI Script, could remove from initial load
					params.parent_sys_id = lParentTasklInfo["sys_id"].value;
					params.parent_active = lParentTasklInfo["active"].display_value;
					params.parent_number = lParentTasklInfo["number"].value;

					var url = this._get_URL_for_Task_Based_on_Prefrences(params.parent_sys_id,'sp');
					url = url + '&state=3&order=1';
					params.reopenParentMsg = " <b>" + 
						gs.getMessage('Tasker - Reopen Parent is not active - start') + 
						" " + '<a href=' + url + '>' + params.parent_number + '</a>' + 
						' ' + gs.getMessage('Tasker - Reopen Parent is not active - end') + '</b>';
				}
				// reopen logic - also in Business Rule Tasker - Tasker - onLoad - set max routes
				// if we do api call back in the UI Script, could remove from initial load
				params.closed_to_long_to_reopen = false;
				params.ReopenMaxDays = gs.getProperty('x_153465_discovert.ReopenMaxDays');
				params.closed_at = gr_task.closed_at;
				var closedAt = new GlideDateTime(params.closed_at);
				// STRY0102134 - Apply Default Schedule to Task Information
				var maxReopenDate;
				if(!gr_task.active){
					var today = new GlideDateTime().getNumericValue();
					// find the end date in the schedule
					var tdc = new TaskerDurationCalculator();
					maxReopenDate = 
						tdc.calculateDateOfAddedBusinessDays(null, params.ReopenMaxDays, closedAt);
					params.closed_to_long_to_reopen = 
						(today > new GlideDateTime(maxReopenDate).getNumericValue());
				}
				params.closeTooLongMsg = params.number + ' ' + 
					gs.getMessage('Tasker - Closed too long to reopen 1') + ' ' + 
					params.ReopenMaxDays + ' ' + 
					gs.getMessage('Tasker - Closed too long to reopen 2') + ' ' + 
					params.closed_at + gs.getMessage('Tasker - Closed too long to reopen 3');

				break;
			case 'c898f2fbdb41a3c8c18c59b2ca9619e0': // "name": "Abstain", "action_name": "Abstain-SendToReview"
			case 'ba139a01db732f00c18c59b2ca96193f': // "name": "Approve", "action_name": "Approve-SendToReview"
			case '77477677db41a3c8c18c59b2ca961932': // "name": "Concur", "action_name": "Concur-SendToReview"
			case '7e48f6f7db41a3c8c18c59b2ca961900': // "name": "NonConcur", "action_name": "NonConcur-SendToReview"
				// the common settings are grouped at the top and another case is below for the differences
				params.table = this.taskTable;
				params.task_sys_id = gr_task.getUniqueValue();
				params.number = gr_task.getValue('number');
				params.placeHolderText = gs.getMessage('Tasker - Please enter Additional Comments');
				params.reviewer_comments = gr_task.getDisplayValue('comments_dt');
				if(!params.reviewer_comments || params.reviewer_comments==null){
					params.reviewer_comments = '';
				}
				params.reviewCommentsRequired = true;
				params.shared = { 
					fields: {
						comments_dt: {
							value: params.reviewer_comments,
							displayValue: params.reviewer_comments,
							sys_mandatory: true,
							mandatory: true,
							placeholder: params.placeHolderText,
							readonly: false
						}
					}
				};

				// the actions in this block are the same with the exception of the view and the title
				// so, added a second switch case to make more concise
				switch (action_sys_id){
					case 'c898f2fbdb41a3c8c18c59b2ca9619e0': // "name": "Abstain", "action_name": "Abstain-SendToReview"
						params.action_name = "Abstain-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Abstain') + ' ' + params.number;
						params.view = 'Abstain_Response';
						break;
					case 'ba139a01db732f00c18c59b2ca96193f': // "name": "Approve", "action_name": "Approve-SendToReview"
						params.action_name = "Approve-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Approve') + ' ' + params.number;
						params.view = 'Accept_Response';
						break;
					case '77477677db41a3c8c18c59b2ca961932': // "name": "Concur", "action_name": "Concur-SendToReview"
						params.action_name = "Concur-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Concur') + ' ' + params.number;
