				params.u_signature_instructions = gr_task.getDisplayValue('u_signature_instructions');
				if(!params.u_signature_instructions || params.u_signature_instructions==null){
					params.u_signature_instructions = '';
				}
				params.review_sign_comments = gr_task.getValue('comments_dt');
				if(!params.review_sign_comments || params.review_sign_comments==null){
					params.review_sign_comments = '';
				}

				// STRY0120264
				params.isSignChecked = gr_task.getValue('u_reviewer_signed');
				params.shared = {
					fields: {
						u_signature_instructions: {
							value: params.u_signature_instructions,
							displayValue: params.u_signature_instructions, 
							sys_mandatory: true, 
							mandatory: true, 
							placeholder: params.placeHolderText},
						// STRY0120264
						u_reviewer_signed: {value: params.isSignChecked, sys_mandatory: true, mandatory: true},
						comments_dt: {
							value: params.review_sign_comments, 
