							sys_mandatory: true, 
							mandatory: true}						
					}
				};

				// the actions in this block are the same with the exception of the view and the title
				// so, added a second switch case to make more concise
				switch (action_sys_id){
					case 'ef909466db11e300c18c59b2ca96198e': // "name": "Approve & Sign", "action_name": "ApproveSign-SendToReview"
						params.action_name = "ApproveSign-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Approve & sign Acknowledgement for') + params.number;
						params.view = 'Confirm_Signature_Instructions';
						break;
					case '2b0abab7db81a3c8c18c59b2ca961992': // "name": "Concur & sign" "action_name": "ConcurSign-SendToReview"
						params.action_name = "ConcurSign-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Concur & sign') + ' ' + params.number;
