							mandatory: true, 
							placeholder: params.placeHolderText, readonly: false},
						rework_comments: {
							value: params.rework_comments, displayValue: params.rework_comments, sys_mandatory: false, mandatory: false},
						provide_response: {
							value: params.provide_response, sys_mandatory: true, mandatory: true}
					}
				};
				break;
			case 'baa96f804f181b00303dc3818110c74e': // "name": "Send to Rework" "action_name": "rework"
				params.table = this.taskTable;
				params.task_sys_id = gr_task.getUniqueValue();
