						rework_comments: {value: params.rework_comments, displayValue: params.rework_comments, sys_mandatory: true, mandatory: true, placeholder: params.placeHolderText}
					}
				};
				break;
			case 'fbe927c04f181b00303dc3818110c7f5': // "name": "Mark Complete" "action_name": "ClosedComplete"
