						rework_comments: {value: params.rework_comments, displayValue: params.rework_comments, sys_mandatory: false, mandatory: false},
						comments_dt: {value: params.reviewer_comments, displayValue: params.reviewer_comments, sys_mandatory: reviewerCommentsMandatory, mandatory: reviewerCommentsMandatory}
