			case '531dde924f68d700303dc3818110c704': // "name": "Request Reassignment", "action_name": "openModalRequestReassignmentSP"
				params.table = this.requestTable;
				params.task_sys_id = gr_task.getUniqueValue();
				params.action_name = "openModalRequestReassignmentSP";
				params.request_sys_id = -1;
				params.title = gs.getMessage('Tasker - Title - Request Reassignment');
				params.view = 'requesttop';
				params.isRequest = true;
				params.request_type = 'Reassignment';
				params.parent = params.task_sys_id;
				break;
			case 'c6e6e812dbd09050dd3d6165ca961990': // "name": "Respond Reassignment", "action_name": "openModalRespondReassignmentSP"
				params.table = this.requestTable;
				params.task_sys_id = gr_task.getUniqueValue();
				params.action_name = "openModalRespondReassignmentSP";
				params.title = gs.getMessage('Tasker - Title - Respond Reassignment Request');
				params.view = 'responsetop';
				params.isRequest = false;
				params.request_type = 'Reassignment';
				params.parent = '';
				requestInfo = this._get_task_request(params.task_sys_id, params.request_type, "In Progress");
				params.request_sys_id = requestInfo.request_sys_id;
				break;
			case '0187ab004f181b00303dc3818110c764': // "name": "Start Work" "action_name": "workInProgress"
			case '403b714edbb017003a8d6be3ca961961': // "name": "Assign Task" "action_name": "assigned"
			case '7703adb74f88d700303dc3818110c784': // "name": "Accept Assignment" "action_name": "AcceptAssignment"
			case 'addRequestAccessGuidhere': // "name": "Request Access for Member(s)"  - no guid today
				break;
			default:
				var errMsg = "Tasker - function: _get_ui_actions_params - an action was requested that isn't implemented.  UI Action sys_id: " + action_sys_id;
				gs.addErrorMessage(errMsg);
				break;
		}
		return params;

	},

	_get_URL_for_Task_Based_on_Prefrences: function(sys_id, current_view){
		var oUserPref = new tasker_User_Form_Preferences();
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(sys_id,current_view);

		var task_url;
		task_url =  
			'../' + url_Properties.portal_url_ref + 
			'?id=' + url_Properties.pageId + 
			'&table=' + this.taskTable + 
			'&sys_id=' + sys_id +
			'&view=' + url_Properties.view;

		return task_url;
	},	



